// Get input
const item = $input.item.json;

// Handle possible nesting:
// item.json.data.data
// item.json.data.data.data
let rootData =
  item?.data?.data?.data ||
  item?.data?.data ||
  item?.data ||
  {};

// Extract main fields
const title = rootData.title || rootData.headline || '';
const article =
  rootData.article ||
  rootData.content ||
  rootData.text ||
  rootData.body ||
  rootData.description ||
  '';

// Calculate wordCount (like your example)
const wordCount =
  article
    ?.split(/\s+/)
    .filter(w => w.length > 0).length || 0;

// Inject wordCount into rootData (like isPaywalled)
rootData.wordCount = wordCount;

// Combine text for relevance checking
const combinedText = (title + ' ' + article).toLowerCase();

// You can replace this with dynamic keywords if needed
const TopicBrandKeywords = ['Hukum', 'iran', 'education']; 

const isRelevant = TopicBrandKeywords.some(keyword =>
  combinedText.includes(keyword.toLowerCase())
);

// Skip if not relevant OR too short
if (!isRelevant || wordCount < 50) {
  return [{
    json: {
      skip: true,
      reason: !isRelevant
        ? 'Not relevant to topic/brand'
        : 'Content too short',
      url: rootData.url || item?.data?.url || '',
      wordCount
    }
  }];
}

// Return enriched rootData
return [{
  json: {
    ...rootData,
    wordCount,
    skip:false
  }
}];

// Parse the AI response and merge with article metadata
const item = $input.item.json;
const articleMeta = $('Keep Only Relevant Articles').item.json;

let analysis = {};
try {
  const raw = item.text || item.response || item.output || '';
  // Strip any accidental markdown fences
  const cleaned = raw.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  analysis = {
    sentiment: 'neutral',
    sentiment_score: 0,
    summary: 'Could not parse AI response.',
    key_topics: [],
    brand_mentions: 0,
    tone: 'neutral',
    action_required: false,
    action_reason: '',
    quote: ''
  };
}

// Sanitise types
const sentiment = String(analysis.sentiment || 'neutral').toLowerCase();
const sentiment_score = parseFloat(analysis.sentiment_score) || 0;
const action_required = analysis.action_required === true || analysis.action_required === 'true';

// Emoji map for sentiment
const emojiMap = { positive: '🟢', neutral: '🟡', negative: '🔴' };
const sentimentEmoji = emojiMap[sentiment] || '⚪';

const sentimentUpper = sentiment.toUpperCase();

return [{
  json: {
    // Article info
    title: articleMeta.title,
    sourceUrl: articleMeta.sourceUrl,
    publishedAt: articleMeta.publishedAt,
    author: articleMeta.author,
    brandName: articleMeta.brandName,
    runDate: articleMeta.runDate,
    slackChannel: articleMeta.slackChannel,
    notionDatabaseId: articleMeta.notionDatabaseId,
    // AI analysis
    sentiment,
    sentiment_score,
    sentimentEmoji,
    summary: analysis.summary || '',
    key_topics: (analysis.key_topics || []).join(', '),
    tone: analysis.tone || 'neutral',
    action_required,
    action_reason: analysis.action_reason || '',
    quote: analysis.quote || '',
    // Formatted for Slack — uses sentimentUpper variable (no Jinja filter)
    slackMessage: `${sentimentEmoji} *${sentimentUpper}* | ${articleMeta.title}\n${analysis.summary}\n🔗 ${articleMeta.sourceUrl}`
  }
}];

