// Aggregate all processed articles into a single daily digest
const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  return [{
    json: {
      digestMessage: `📰 *Daily Sentiment Report*\n\nNo articles were processed today.`,
      total: 0,
      counts: { positive: 0, neutral: 0, negative: 0 },
      avgScore: "0.00",
      actionCount: 0
    }
  }];
}

const articles = allItems.map(i => i.json);

// Count sentiments
const counts = { positive: 0, neutral: 0, negative: 0 };
for (const a of articles) {
  const s = (a.sentiment || "neutral").toLowerCase();
  if (counts[s] !== undefined) {
    counts[s]++;
  }
}

const total = articles.length;

const avgScore = (
  articles.reduce((sum, a) => sum + (parseFloat(a.sentiment_score) || 0), 0) 
  / total
).toFixed(2);

const actionItems = articles.filter(a => a.action_required === true);

// Use current date automatically
const runDate = new Date().toISOString();

// Build Slack digest
let digest = `📰 *Daily Sentiment Report*\n`;
digest += `📅 ${runDate.slice(0, 10)}\n\n`;
digest += `*Overview:* ${total} articles analyzed\n`;
digest += `🟢 Positive: ${counts.positive} | 🟡 Neutral: ${counts.neutral} | 🔴 Negative: ${counts.negative}\n`;
digest += `📊 Avg Sentiment Score: ${avgScore}\n\n`;

if (actionItems.length > 0) {
  digest += `⚠️ *${actionItems.length} item(s) need attention:*\n`;
  for (const a of actionItems) {
    digest += `• ${a.title} — ${a.action_reason}\n`;
    digest += `  🔗 ${a.sourceUrl}\n`;
  }
  digest += "\n";
}

digest += `*Top Articles Today:*\n`;
for (const a of articles.slice(0, 5)) {
  const summaryPreview = (a.summary || "").slice(0, 120);
  digest += `${a.sentimentEmoji || "⚪"} ${a.title}\n`;
  digest += `  _${summaryPreview}..._\n`;
  digest += `  🔗 ${a.sourceUrl}\n\n`;
}

return [{
  json: {
    digestMessage: digest,
    total,
    counts,
    avgScore,
    actionCount: actionItems.length,
    runDate
  }
}];

// Get data from previous node
const inputData = $input.all();

// Default empty array
let urls = [];

// Extract URLs safely (correct nested path)
if (
  inputData.length > 0 &&
  inputData[0].json?.data?.data?.urls &&
  Array.isArray(inputData[0].json.data.data.urls)
) {
  urls = inputData[0].json.data.data.urls;
}

// Return each URL as separate item
return urls.map((url, index) => ({
  json: {
    url,
    index: index + 1
  }
}));
